9:     function isMember(chatData) {
10:       return isSignedIn() && request.auth.uid in chatData.members;
11:     }
12: 
13:     function isAdmin(chatData) {
14:       return isSignedIn() && chatData.admins[request.auth.uid] == true;
15:     }
16: 
17:     // User profiles
18:     match /users/{userId} {
19:       allow read: if isSignedIn();
20:       allow write: if request.auth.uid == userId;
21:       
22:       // Contacts subcollection
23:       match /contacts/{contactId} {
24:         allow read, write: if isSignedIn() && request.auth.uid == userId;
25:       }
26:     }
27: 
28:     // Chats
29:     match /chats/{chatId} {
30:       allow read: if isMember(resource.data);
31:       allow create: if isSignedIn() && request.auth.uid in request.resource.data.members;
32:       allow update: if isMember(resource.data);
33:       // Only group admins can delete the chat document
34:       allow delete: if isAdmin(resource.data);
35:       
36:       // Messages subcollection
37:       match /messages/{messageId} {
38:         allow read: if isMember(get(/databases/$(database)/documents/chats/$(chatId)).data);
39:         allow create: if isMember(get(/databases/$(database)/documents/chats/$(chatId)).data) 
