6: 
7: /**
8:  * For 1-on-1 chats, generates a stable key from the two member UIDs
9:  * regardless of their order in the array.
10:  */
11: function pairKey(chat: Chat): string | null {
12:   if (chat.type !== 'one-to-one' || !chat.members || chat.members.length < 2) return null;
13:   return [...chat.members].sort().join('|');
14: }
15: 
16: /**
17:  * Deduplicates 1-on-1 chats: for each unique pair of members,
18:  * keeps the most recent chat (largest lastMessageAt or createdAt)
19:  * and schedules the older duplicates for deletion.
20:  */
21: function deduplicateChats(chats: Chat[], onDeleteIds: (ids: string[]) => void): Chat[] {
22:   const seen = new Map<string, Chat>();
23:   const toDelete: string[] = [];
24: 
25:   for (const chat of chats) {
26:     const key = pairKey(chat);
27:     if (!key) continue; // groups — skip
28: 
29:     const existing = seen.get(key);
30:     if (!existing) {
31:       seen.set(key, chat);
32:     } else {
33:       // Keep whichever has the newer lastMessageAt; delete the older one
34:       const chatTime = chat.lastMessageAt || 0;
35:       const existingTime = existing.lastMessageAt || 0;
36:       if (chatTime >= existingTime) {
37:         toDelete.push(existing.id);
38:         seen.set(key, chat);
39:       } else {
40:         toDelete.push(chat.id);
41:       }
42:     }
43:   }
44: 
45:   if (toDelete.length > 0) {
46:     onDeleteIds(toDelete);
47:   }
48: 
49:   // Build final list: keep all groups + de-duped 1-to-1s
50:   const groups = chats.filter(c => c.type !== 'one-to-one');
51:   return [...groups, ...Array.from(seen.values())];
52: }
